            if (v3Global.opt.threads() > 1) {
                putns(nodep, "vlSymsp->__Vcoverage[");
                puts(cvtToStr(nodep->declp()->dataDeclThisp()->binNum()));
                puts("].fetch_add(1, std::memory_order_relaxed);\n");
            } else {
                putns(nodep, "++(vlSymsp->__Vcoverage[");
                puts(cvtToStr(nodep->declp()->dataDeclThisp()->binNum()));
                puts("]);\n");
