int main(int argc, char** argv) {
    // General initialization
    std::ios::sync_with_stdio();
    VlOs::DeltaWallTime wallTimeTotal{true};
    VlOs::DeltaCpuTime cpuTimeTotal{true};

    time_t randseed;
